<?php namespace App\Repositories\Accounting;use App\Repositories\BaseRepository;use App\Models\Accounting\Budget;use Illuminate\Database\Eloquent\Collection;class BudgetRepository extends BaseRepository{    public function __construct(Budget $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByFiscalYear(int $year): Collection    {        return $this->findByField('fiscal_year', $year);    }    public function findByCategory(string $category): Collection    {        return $this->findByField('category', $category);    }    public function findByAccount(int $chartOfAccountId): Collection    {        return $this->findByField('chart_of_account_id', $chartOfAccountId);    }    public function getActiveBudgets(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByAmountRange(float $min, float $max): Collection    {        return $this->query()->whereBetween('budget_amount', [$min, $max])->get();    }    public function searchBudgets(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getBudgetUtilization(int $budgetId): array    {        $budget = $this->getById($budgetId);        $spent = $budget->actual_spent ?? 0;        $allocated = $budget->budget_amount;        return [            'allocated' => $allocated,            'spent' => $spent,            'remaining' => $allocated - $spent,            'utilization_percentage' => $allocated > 0 ? round(($spent / $allocated) * 100, 2) : 0,        ];    }    public function getOverBudget(): Collection    {        return $this->query()->where('actual_spent', '>', 'budget_amount')->get();    }    public function approveBudget(int $id, ?string $approvedBy = null): bool    {        $data = ['status' => 'approved', 'approved_at' => now()];        if ($approvedBy) {            $data['approved_by'] = $approvedBy;        }        return $this->update($id, $data);    }}